using System;

[AttributeUsage(AttributeTargets.All)]
public class TypeAttr : Attribute
{
    public TypeAttr(string name) { Name = name; }
    public string Name { get; }
}

[AttributeUsage(AttributeTargets.All)]
public class MethodAttr : Attribute
{
    public MethodAttr(string name) { Name = name; }
    public string Name { get; }
}

[AttributeUsage(AttributeTargets.All)]
public class ParamAttr : Attribute
{
    public ParamAttr(string name) { Name = name; }
    public string Name { get; }
}

[TypeAttr("service")]
public interface IReportService
{
    [MethodAttr("query")]
    string QueryReport([ParamAttr("report id")] int id);
}

[YS.Knife.ExposeApi(typeof(IReportService), TypeAttributePatterns = new string[] { "TypeAttr" }, MethodAttributePatterns = new string[] { "MethodAttr" }, ParameterAttributePatterns = new string[] { "ParamAttr" })]
public class TestController
{
}

