#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    [global::TypeAttr("service")]
    public class ReportController : ControllerBase
    {
        private readonly global::IReportService iReportService;
        public ReportController(global::IReportService iReportService)
        {
            this.iReportService = iReportService;
        }

        [Route("QueryReport/{id}")]
        [HttpGet]
        [global::MethodAttr("query")]
        public string QueryReport([FromRoute] [global::ParamAttr("report id")] int id)
        {
            return this.iReportService.QueryReport(id);                    
        }
    }
}
